int longestSubarray(vector<int>& nums, int target) {
    map<int, int> prefix_sum_map;
    int max_length = 0;
    int prefix_sum = 0;
    for(int i = 0; i < nums.size(); i++) {
        prefix_sum += nums[i];
        if(prefix_sum_map.find(prefix_sum - target) != prefix_sum_map.end())
            max_length = max(max_length, i - prefix_sum_map[prefix_sum - target]);
        if(!prefix_sum_map.count(prefix_sum))
            prefix_sum_map[prefix_sum] = i;
    }
    return max_length;
}
int main() {
    int n; cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++)
        cin >> nums[i];
    int target; cin >> target;
    cout << longestSubarray(nums, target) << endl;
    return 0;
}

