public int longestSubarray(int[] nums, int target) {
    Map<Integer, Integer> prefix_sum_map = new HashMap<>();
    int max_length = 0;
    int prefix_sum = 0;
    for(int i = 0; i < nums.length; i++) {
        prefix_sum += nums[i];
        if(prefix_sum_map.containsKey(prefix_sum - target))
            max_length = Math.max(max_length, i - prefix_sum_map.get(prefix_sum - target));
        if(!prefix_sum_map.containsKey(prefix_sum))
            prefix_sum_map.put(prefix_sum, i);
    }
    return max_length;
}
public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int[] nums = new int[n];
    for(int i = 0; i < n; i++)
        nums[i] = sc.nextInt();
    int target = sc.nextInt();
    System.out.println(longestSubarray(nums, target));
}
